-- ============================================================================
-- 0023_rebuild_affected_historical.sql
--
-- BACKGROUND
--   Reconciliation against per_meter_final.csv after migration 0022 found
--   147 rows + ~$28K of cumulative discrepancies across 25 (property, GL)
--   pairs. Two distinct causes:
--
--   1. Multi-row groups (same prop+gl+acct+year+month with multiple legitimate
--      rows). Migration 0022 restored most but assumed the survivor was in
--      DB. For some pairs the survivor was MISSING (likely from 0015c's
--      first run failing mid-batch), so 0022's -r2..-rN inserts left a gap.
--
--   2. Single-row groups where the DB has slightly different amounts than
--      per_meter_final expects (~$28K cumulative drift), most visible on
--      FedEx (GL 5620) at 14 properties. Caused by 0015c's two runs
--      inserting different amount versions; 0017 dedupe kept the wrong one.
--
-- WHAT THIS MIGRATION DOES
--   For 20 (property, GL) pairs (5 of the original 25 are excluded — see
--   below), DELETE all `historical-%` invoices and reinsert canonical rows
--   from per_meter_final with consistent -r1..-rN source_references for
--   every (account, year, month) group.
--
-- AFFECTED PAIRS (20)
--   GL 5114 (vacant electric):  514, 558, 562, 604, 608
--   GL 5116 (clubhouse):        601
--   GL 5120 (water):            515
--   GL 5125 (sewer):            515
--   GL 5620 (FedEx):            508, 514, 515, 516, 555, 558, 559, 560,
--                               561, 562, 601, 602, 603, 604
--
-- NOT TOUCHED (5 pairs deferred — water sub-line-item issue)
--   558/5125, 559/5120, 560/5120, 561/5120, 562/5120
--   These pairs have "Storm Water" and "Env Fee" line items in per_meter
--   that lack a Sage account number. 0015 mapped them inconsistently —
--   needs case-by-case investigation. The DB state for these is unchanged.
--
-- Vendor + UA lookups use current records (post 0018-0021). Historical
-- invoices are pre-pipeline (status=posted_to_sage, no PDFs/notes/edits).
-- ============================================================================

do $migration$
declare
  v_deleted       int;
  v_pending       int;
  v_unresolvable  int;
  v_inserted      int;
begin

  -- Step 1 — delete historical rows for affected (property, gl) pairs ------

  with affected_pairs as (
    select * from (values
    ('508', '5620'),
    ('514', '5114'),
    ('514', '5620'),
    ('515', '5120'),
    ('515', '5125'),
    ('515', '5620'),
    ('516', '5620'),
    ('555', '5620'),
    ('558', '5114'),
    ('558', '5620'),
    ('559', '5620'),
    ('560', '5620'),
    ('561', '5620'),
    ('562', '5114'),
    ('562', '5620'),
    ('601', '5116'),
    ('601', '5620'),
    ('602', '5620'),
    ('603', '5620'),
    ('604', '5114'),
    ('604', '5620'),
    ('608', '5114')
    ) as t(prop_code, gl_code)
  )
  delete from invoices i
   using properties p, gl_accounts g, affected_pairs ap
   where i.property_id   = p.id
     and i.gl_account_id = g.id
     and p.code          = ap.prop_code
     and g.code          = ap.gl_code
     and i.source_reference like 'historical-%';

  get diagnostics v_deleted = row_count;
  raise notice '[0023] Step 1: deleted % stale historical invoices.', v_deleted;

  -- Step 2 — stage canonical rows -------------------------------------------

  create temp table _rebuild (
    property_code     text,
    gl_account_code   int,
    account_number    text,
    year              int,
    month             int,
    amount            numeric,
    source_reference  text
  ) on commit drop;


  select count(*) into v_pending from _rebuild;
  raise notice '[0023] Step 2: staged % canonical rows.', v_pending;

  -- Step 3 — resolve property + gl + UA + vendor ----------------------------

  create temp table _rb_resolved on commit drop as
  select
    rb.*,
    p.id   as property_id,
    g.id   as gl_account_id,
    ua.id  as utility_account_id,
    ua.vendor_id
  from _rebuild rb
  left join properties     p  on p.code = rb.property_code
  left join gl_accounts    g  on g.code = rb.gl_account_code::text
  left join utility_accounts ua
    on ua.property_id    = p.id
   and ua.gl_account_id  = g.id
   and ua.account_number is not distinct from rb.account_number;

  select count(*) into v_unresolvable
    from _rb_resolved
   where utility_account_id is null
      or vendor_id is null;

  if v_unresolvable > 0 then
    raise notice '[0023] WARNING: % rows could not resolve to a UA. Listing (up to 30):', v_unresolvable;
    declare r record;
    begin
      for r in (
        select distinct property_code, gl_account_code, account_number,
               (case when utility_account_id is null then 'no UA exists'
                     when vendor_id is null then 'UA exists but vendor_id is NULL'
                     else 'unknown' end) as reason
        from _rb_resolved
        where utility_account_id is null or vendor_id is null
        limit 30
      ) loop
        raise notice '  prop=% gl=% acct="%" -> %',
          r.property_code, r.gl_account_code, r.account_number, r.reason;
      end loop;
    end;
  end if;

  -- Step 4 — insert ---------------------------------------------------------

    utility_account_id, property_id, vendor_id, gl_account_id,
    invoice_number, invoice_date, service_period_start, service_period_end,
    current_charges, total_amount_due, gl_coding,
    status, source, source_reference,
    submitted_at, approved_at, sage_posted_at,
    exclude_from_baseline
  )
  select
    r.utility_account_id, r.property_id, r.vendor_id, r.gl_account_id,
    r.source_reference,
    make_date(r.year, r.month, 15),
    make_date(r.year, r.month, 1),
    (make_date(r.year, r.month, 1) + interval '1 month' - interval '1 day')::date,
    r.amount, r.amount,
    '500-' || r.property_code || '-' || r.gl_account_code::text || '.00',
    'posted_to_sage'::invoice_status,
    'manual',
    r.source_reference,
    now(), now(), now(),
    false
  from _rb_resolved r
  where r.utility_account_id is not null
    and r.vendor_id is not null;

  get diagnostics v_inserted = row_count;
  raise notice '[0023] Step 4: inserted % canonical historical invoices.', v_inserted;

  raise notice '[0023] Done. Net change: -% +% = %.', v_deleted, v_inserted, v_inserted - v_deleted;

end $migration$;
